const Q_FRENCH_2010=[{"id": "objective>French>2010>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">TEXTES DE COMPRÉHENSION <br/> Lisez les deux textes ci-dessous et répondez aux questions qui les suivent. <br/> TEXTE I <br/> Les Sports <br/> Près de quinze millions de Français n'ont jamais pratiqué de sport. Ce qui ne veut pas dire qu'ils <br/> soient inactifs... Mais parmi ceux qui pratiquent du sport, on trouvera surtout; Les chasseurs, les <br/> pêcheurs, les joueurs de boules et de pétanque, les skieurs et les amateurs de voile. Les chasseurs <br/> sont au nombre d'environ 2,5 millions. Ils achètent chaque anneé un permi et considèrent leur <br/> activité avec tellement de sérieux que leur Fédération avait adressé une lettre aux différents <br/> candidats lors des élections légistlatives de mars 1978 pour leur demander quel était leur <br/> programme de développement de la chasse. Le grand jour pour tous les chasseurs de France est <br/> naturellement le jour de l'ouverture de la chasse. <br/> Les pêcheurs sont encore plus nombreux puisque leur nombre est estimé à 5 millions. Les <br/> joueurs de boules et de pétanque sont surtout très nombreux dans le midi de la France. Plus <br/> proches du sport proprement dit sont les skieurs et les amateurs de voile don't le nombre <br/> augmente chaque année considérablement. <br/> Le mouvement actuel de retour à la nature favorise une renaissance de la marche à pied, <br/> de la promenade à bicyclette ou à cheval. Pour les autres sports, il faut bien dire qu'ils attirent <br/> plus de spectateurs que de participants. <br/> C'est le cas en particulier des trois grands événements sportifs de l'année: le Tour de <br/> France (course cycliste), la Coupe de France de football et le Tournoi des Cinq Nations où <br/> s'affrontent des équipes de rugby à 15, représentant la France, l'Angleterre, l'Ecosse, le Pays des <br/> Galles et l'Irlande. <br/> Adapté:Michel Paoletti et Ross Stede (1980) <br/>  <br/> D'après le texte, généralement, les Français</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ne font pas de sport</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sont tous sportifs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sont tous actifs.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n'aiment pas la chasse.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">D'après le texte, généralement, les Français préfèrent regarder le sport plutôt que d'y participer activement. <br/> The French generally prefer to watch sports rather than take part in them.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> TEXTES DE COMPRÉHENSION <br/> Lisez les deux textes ci-dessous et répondez aux questions qui les suivent. <br/> TEXTE I <br/> Les Sports <br/> Près de quinze millions de Français n'ont jamais pratiqué de sport. Ce qui ne veut pas dire qu'ils <br/> soient inactifs... Mais parmi ceux qui pratiquent du sport, on trouvera surtout; Les chasseurs, les <br/> pêcheurs, les joueurs de boules et de pétanque, les skieurs et les amateurs de voile. Les chasseurs <br/> sont au nombre d'environ 2,5 millions. Ils achètent chaque anneé un permi et considèrent leur <br/> activité avec tellement de sérieux que leur Fédération avait adressé une lettre aux différents <br/> candidats lors des élections légistlatives de mars 1978 pour leur demander quel était leur <br/> programme de développement de la chasse. Le grand jour pour tous les chasseurs de France est <br/> naturellement le jour de l'ouverture de la chasse. <br/> Les pêcheurs sont encore plus nombreux puisque leur nombre est estimé à 5 millions. Les <br/> joueurs de boules et de pétanque sont surtout très nombreux dans le midi de la France. Plus <br/> proches du sport proprement dit sont les skieurs et les amateurs de voile don't le nombre <br/> augmente chaque année considérablement. <br/> Le mouvement actuel de retour à la nature favorise une renaissance de la marche à pied, <br/> de la promenade à bicyclette ou à cheval. Pour les autres sports, il faut bien dire qu'ils attirent <br/> plus de spectateurs que de participants. <br/> C'est le cas en particulier des trois grands événements sportifs de l'année: le Tour de <br/> France (course cycliste), la Coupe de France de football et le Tournoi des Cinq Nations où <br/> s'affrontent des équipes de rugby à 15, représentant la France, l'Angleterre, l'Ecosse, le Pays des <br/> Galles et l'Irlande. <br/> Adapté:Michel Paoletti et Ross Stede (1980) <br/> Quelle est la population des pêcheurs français?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">environ 7,5 millions.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7 millions.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 millions.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,5 millions.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The text states that 'Les pêcheurs sont encore plus nombreux puisque leur nombre est estimé à 5 millions' which translates to 'Fishermen are even more numerous since their number is estimated at 5 million'. This implies that the population of French fishermen is around 5 million, hence option 3 '5 millions' is correct.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> TEXTES DE COMPRÉHENSION <br/> Lisez les deux textes ci-dessous et répondez aux questions qui les suivent. <br/> TEXTE I <br/> Les Sports <br/> Près de quinze millions de Français n'ont jamais pratiqué de sport. Ce qui ne veut pas dire qu'ils <br/> soient inactifs... Mais parmi ceux qui pratiquent du sport, on trouvera surtout; Les chasseurs, les <br/> pêcheurs, les joueurs de boules et de pétanque, les skieurs et les amateurs de voile. Les chasseurs <br/> sont au nombre d'environ 2,5 millions. Ils achètent chaque anneé un permi et considèrent leur <br/> activité avec tellement de sérieux que leur Fédération avait adressé une lettre aux différents <br/> candidats lors des élections légistlatives de mars 1978 pour leur demander quel était leur <br/> programme de développement de la chasse. Le grand jour pour tous les chasseurs de France est <br/> naturellement le jour de l'ouverture de la chasse. <br/> Les pêcheurs sont encore plus nombreux puisque leur nombre est estimé à 5 millions. Les <br/> joueurs de boules et de pétanque sont surtout très nombreux dans le midi de la France. Plus <br/> proches du sport proprement dit sont les skieurs et les amateurs de voile don't le nombre <br/> augmente chaque année considérablement. <br/> Le mouvement actuel de retour à la nature favorise une renaissance de la marche à pied, <br/> de la promenade à bicyclette ou à cheval. Pour les autres sports, il faut bien dire qu'ils attirent <br/> plus de spectateurs que de participants. <br/> C'est le cas en particulier des trois grands événements sportifs de l'année: le Tour de <br/> France (course cycliste), la Coupe de France de football et le Tournoi des Cinq Nations où <br/> s'affrontent des équipes de rugby à 15, représentant la France, l'Angleterre, l'Ecosse, le Pays des <br/> Galles et l'Irlande. <br/> Adapté:Michel Paoletti et Ross Stede (1980) <br/> Les joueurs de boules et de pétanque sont très nombreux</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">au Sud de la France</div>", "<div style=\"font-family:Cambria;font-size:17px;\">au nord de la France</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hors de France</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loin de la France.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The text states that 'Les joueurs de boules et de pétanque sont surtout très nombreux dans le midi de la France' which translates to 'Boules and pétanque players are especially very numerous in the south of France'. This implies that there is a high number of boules and pétanque players in the south of France, hence option 1 'au Sud de la France' (in the South of France) is correct.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> TEXTES DE COMPRÉHENSION <br/> Lisez les deux textes ci-dessous et répondez aux questions qui les suivent. <br/> TEXTE I <br/> Les Sports <br/> Près de quinze millions de Français n'ont jamais pratiqué de sport. Ce qui ne veut pas dire qu'ils <br/> soient inactifs... Mais parmi ceux qui pratiquent du sport, on trouvera surtout; Les chasseurs, les <br/> pêcheurs, les joueurs de boules et de pétanque, les skieurs et les amateurs de voile. Les chasseurs <br/> sont au nombre d'environ 2,5 millions. Ils achètent chaque anneé un permi et considèrent leur <br/> activité avec tellement de sérieux que leur Fédération avait adressé une lettre aux différents <br/> candidats lors des élections légistlatives de mars 1978 pour leur demander quel était leur <br/> programme de développement de la chasse. Le grand jour pour tous les chasseurs de France est <br/> naturellement le jour de l'ouverture de la chasse. <br/> Les pêcheurs sont encore plus nombreux puisque leur nombre est estimé à 5 millions. Les <br/> joueurs de boules et de pétanque sont surtout très nombreux dans le midi de la France. Plus <br/> proches du sport proprement dit sont les skieurs et les amateurs de voile don't le nombre <br/> augmente chaque année considérablement. <br/> Le mouvement actuel de retour à la nature favorise une renaissance de la marche à pied, <br/> de la promenade à bicyclette ou à cheval. Pour les autres sports, il faut bien dire qu'ils attirent <br/> plus de spectateurs que de participants. <br/> C'est le cas en particulier des trois grands événements sportifs de l'année: le Tour de <br/> France (course cycliste), la Coupe de France de football et le Tournoi des Cinq Nations où <br/> s'affrontent des équipes de rugby à 15, représentant la France, l'Angleterre, l'Ecosse, le Pays des <br/> Galles et l'Irlande. <br/> Adapté:Michel Paoletti et Ross Stede (1980) <br/> Qui participe au Tour de France? Les</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chasseurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chauffeurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclistes.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The text mentions 'le Tour de France (course cycliste)', which translates to 'the Tour de France (cycling race)'. Therefore, it is the cyclists who participate in the Tour de France.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> TEXTES DE COMPRÉHENSION <br/> Lisez les deux textes ci-dessous et répondez aux questions qui les suivent. <br/> TEXTE I <br/> Les Sports <br/> Près de quinze millions de Français n'ont jamais pratiqué de sport. Ce qui ne veut pas dire qu'ils <br/> soient inactifs... Mais parmi ceux qui pratiquent du sport, on trouvera surtout; Les chasseurs, les <br/> pêcheurs, les joueurs de boules et de pétanque, les skieurs et les amateurs de voile. Les chasseurs <br/> sont au nombre d'environ 2,5 millions. Ils achètent chaque anneé un permi et considèrent leur <br/> activité avec tellement de sérieux que leur Fédération avait adressé une lettre aux différents <br/> candidats lors des élections légistlatives de mars 1978 pour leur demander quel était leur <br/> programme de développement de la chasse. Le grand jour pour tous les chasseurs de France est <br/> naturellement le jour de l'ouverture de la chasse. <br/> Les pêcheurs sont encore plus nombreux puisque leur nombre est estimé à 5 millions. Les <br/> joueurs de boules et de pétanque sont surtout très nombreux dans le midi de la France. Plus <br/> proches du sport proprement dit sont les skieurs et les amateurs de voile don't le nombre <br/> augmente chaque année considérablement. <br/> Le mouvement actuel de retour à la nature favorise une renaissance de la marche à pied, <br/> de la promenade à bicyclette ou à cheval. Pour les autres sports, il faut bien dire qu'ils attirent <br/> plus de spectateurs que de participants. <br/> C'est le cas en particulier des trois grands événements sportifs de l'année: le Tour de <br/> France (course cycliste), la Coupe de France de football et le Tournoi des Cinq Nations où <br/> s'affrontent des équipes de rugby à 15, représentant la France, l'Angleterre, l'Ecosse, le Pays des <br/> Galles et l'Irlande. <br/> Adapté:Michel Paoletti et Ross Stede (1980) <br/> Combien de pays participent au Tournoi de Rugby?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Quatre.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cinq.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dix.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quinze.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The text mentions 'le Tournoi des Cinq Nations où s'affrontent des équipes de rugby à 15, représentant la France, l'Angleterre, l'Ecosse, le Pays des Galles et l'Irlande.' This translates to 'the Five Nations Tournament where 15-man rugby teams compete, representing France, England, Scotland, Wales, and Ireland.' Therefore, five countries participate in the Rugby Tournament.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">TEXTE II <br/> Lorsque j'étais enfant, ce que je faisais <br/> Mes souvenirs d'enfance sont remplis de beaucoup d'expériences intéressantes. Lorsque <br/> j'étais enfant, je cherchais toujours à être dans la compagnie des autres enfants comme moi. <br/> J'avais horreur de rester seul, si bien que je pleurais pendant des heures si je ne me voyais qu' <br/> entouré de solitude. <br/> Ma mère aimait m'acheter des friandises, mais mon père était un peu avare sur des <br/> questions de friandises. Chaque fois que maman n'était pas à la maison pour m'en donner, je <br/> devais faire semblant d'être malade pour que papa m'en achète. Et il faut imaginer combien de <br/> fois il me disait: \"Je sais que tu seras bientôt guéri\". <br/> Comme j'étais l'enfant unique de mes parents à cette époque-là, l'on comprendrait <br/> facilement pourquoi mon père, malgré son avarice, était bien indulgent envers moi. <br/> C'était à l'école que je profitais le plus de sa gentillesse et, bien sûr de celle de ma mère. <br/> Je me rappelle avoir demandé trois fois l'argent pour un seul livre de calcul! Je n'avais qu'à <br/> demander, et ils me donnaient volontiers. Mais, quelquefois pour y arriver, il fallait mentir. Si je <br/> mentais pour demander un peu d'argent, ce n'était pas par méchanceté; c'était plutôt parce que je <br/> ne savais pas mieux. J'ai trouvé le jeu gai. <br/> D'ailleurs, je ne faisais pas que mentir. <br/> En classe, j'avais la réputation d'être l'un des meilleurs élèves. Même les instituteurs les <br/> moins indulgents ont reconnu en moi cette petite qualité. Je faisais l'école buissonnière, c'est <br/> vrai, mais je faisais de mon mieux pour rattraper le retard. Il est nécessaire aussi de signaler que <br/> mon habitude de faire l'école buissonnière s'arrêtait après la première semaine de la rentrée pour <br/> ne reprendre qu'après l'examen. Quand j'y pense aujourd 'hui, j'avoue que je trouve cette <br/> habitude maligne. N'est ce pas pour éviter les travaux de champs? <br/> Néanmoins, je passais une grande partie de mes vacances à la ferme non avec mon père, <br/> mais avec mon grand père. Mon père avait sa ferme, mais on s'amusait mieux avec mon grandpère. <br/> C'est chez celui-ci qu'on mangeait mieux. <br/> D'après Ajiboye, Tunde (2008) First Essays in French. <br/>  <br/> L'auteur était gâté surtout</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pendant son enfance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">à l'école</div>", "<div style=\"font-family:Cambria;font-size:17px;\">à l'âge adulte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pendant les vacances.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The author was especially spoiled at school during his childhood.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> TEXTE II <br/> Lorsque j'étais enfant, ce que je faisais <br/> Mes souvenirs d'enfance sont remplis de beaucoup d'expériences intéressantes. Lorsque <br/> j'étais enfant, je cherchais toujours à être dans la compagnie des autres enfants comme moi. <br/> J'avais horreur de rester seul, si bien que je pleurais pendant des heures si je ne me voyais qu' <br/> entouré de solitude. <br/> Ma mère aimait m'acheter des friandises, mais mon père était un peu avare sur des <br/> questions de friandises. Chaque fois que maman n'était pas à la maison pour m'en donner, je <br/> devais faire semblant d'être malade pour que papa m'en achète. Et il faut imaginer combien de <br/> fois il me disait: \"Je sais que tu seras bientôt guéri\". <br/> Comme j'étais l'enfant unique de mes parents à cette époque-là, l'on comprendrait <br/> facilement pourquoi mon père, malgré son avarice, était bien indulgent envers moi. <br/> C'était à l'école que je profitais le plus de sa gentillesse et, bien sûr de celle de ma mère. <br/> Je me rappelle avoir demandé trois fois l'argent pour un seul livre de calcul! Je n'avais qu'à <br/> demander, et ils me donnaient volontiers. Mais, quelquefois pour y arriver, il fallait mentir. Si je <br/> mentais pour demander un peu d'argent, ce n'était pas par méchanceté; c'était plutôt parce que je <br/> ne savais pas mieux. J'ai trouvé le jeu gai. <br/> D'ailleurs, je ne faisais pas que mentir. <br/> En classe, j'avais la réputation d'être l'un des meilleurs élèves. Même les instituteurs les <br/> moins indulgents ont reconnu en moi cette petite qualité. Je faisais l'école buissonnière, c'est <br/> vrai, mais je faisais de mon mieux pour rattraper le retard. Il est nécessaire aussi de signaler que <br/> mon habitude de faire l'école buissonnière s'arrêtait après la première semaine de la rentrée pour <br/> ne reprendre qu'après l'examen. Quand j'y pense aujourd 'hui, j'avoue que je trouve cette <br/> habitude maligne. N'est ce pas pour éviter les travaux de champs? <br/> Néanmoins, je passais une grande partie de mes vacances à la ferme non avec mon père, <br/> mais avec mon grand père. Mon père avait sa ferme, mais on s'amusait mieux avec mon grandpère. <br/> C'est chez celui-ci qu'on mangeait mieux. <br/> D'après Ajiboye, Tunde (2008) First Essays in French. <br/> Au momeut de l' histoire,les parents de l'auteur</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">étaient très riches</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avaient beaucoup d'enfants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">étaient très avares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avaient un seul enfant.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The text states 'Comme j'étais l'enfant unique de mes parents à cette époque-là', which translates to 'As I was the only child of my parents at that time'. This matches with the fourth option 'avaient un seul enfant', which means 'had only one child'.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> TEXTE II <br/> Lorsque j'étais enfant, ce que je faisais <br/> Mes souvenirs d'enfance sont remplis de beaucoup d'expériences intéressantes. Lorsque <br/> j'étais enfant, je cherchais toujours à être dans la compagnie des autres enfants comme moi. <br/> J'avais horreur de rester seul, si bien que je pleurais pendant des heures si je ne me voyais qu' <br/> entouré de solitude. <br/> Ma mère aimait m'acheter des friandises, mais mon père était un peu avare sur des <br/> questions de friandises. Chaque fois que maman n'était pas à la maison pour m'en donner, je <br/> devais faire semblant d'être malade pour que papa m'en achète. Et il faut imaginer combien de <br/> fois il me disait: \"Je sais que tu seras bientôt guéri\". <br/> Comme j'étais l'enfant unique de mes parents à cette époque-là, l'on comprendrait <br/> facilement pourquoi mon père, malgré son avarice, était bien indulgent envers moi. <br/> C'était à l'école que je profitais le plus de sa gentillesse et, bien sûr de celle de ma mère. <br/> Je me rappelle avoir demandé trois fois l'argent pour un seul livre de calcul! Je n'avais qu'à <br/> demander, et ils me donnaient volontiers. Mais, quelquefois pour y arriver, il fallait mentir. Si je <br/> mentais pour demander un peu d'argent, ce n'était pas par méchanceté; c'était plutôt parce que je <br/> ne savais pas mieux. J'ai trouvé le jeu gai. <br/> D'ailleurs, je ne faisais pas que mentir. <br/> En classe, j'avais la réputation d'être l'un des meilleurs élèves. Même les instituteurs les <br/> moins indulgents ont reconnu en moi cette petite qualité. Je faisais l'école buissonnière, c'est <br/> vrai, mais je faisais de mon mieux pour rattraper le retard. Il est nécessaire aussi de signaler que <br/> mon habitude de faire l'école buissonnière s'arrêtait après la première semaine de la rentrée pour <br/> ne reprendre qu'après l'examen. Quand j'y pense aujourd 'hui, j'avoue que je trouve cette <br/> habitude maligne. N'est ce pas pour éviter les travaux de champs? <br/> Néanmoins, je passais une grande partie de mes vacances à la ferme non avec mon père, <br/> mais avec mon grand père. Mon père avait sa ferme, mais on s'amusait mieux avec mon grandpère. <br/> C'est chez celui-ci qu'on mangeait mieux. <br/> D'après Ajiboye, Tunde (2008) First Essays in French. <br/> Selon le texte, l'auteur était un enfant</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">paresseux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intelligent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">idiot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frustré.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The text states 'En classe, j'avais la réputation d'être l'un des meilleurs élèves', which translates to 'In class, I had the reputation of being one of the best students'. This suggests that the author was intelligent, which matches with the second option 'intelligent'.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> TEXTE II <br/> Lorsque j'étais enfant, ce que je faisais <br/> Mes souvenirs d'enfance sont remplis de beaucoup d'expériences intéressantes. Lorsque <br/> j'étais enfant, je cherchais toujours à être dans la compagnie des autres enfants comme moi. <br/> J'avais horreur de rester seul, si bien que je pleurais pendant des heures si je ne me voyais qu' <br/> entouré de solitude. <br/> Ma mère aimait m'acheter des friandises, mais mon père était un peu avare sur des <br/> questions de friandises. Chaque fois que maman n'était pas à la maison pour m'en donner, je <br/> devais faire semblant d'être malade pour que papa m'en achète. Et il faut imaginer combien de <br/> fois il me disait: \"Je sais que tu seras bientôt guéri\". <br/> Comme j'étais l'enfant unique de mes parents à cette époque-là, l'on comprendrait <br/> facilement pourquoi mon père, malgré son avarice, était bien indulgent envers moi. <br/> C'était à l'école que je profitais le plus de sa gentillesse et, bien sûr de celle de ma mère. <br/> Je me rappelle avoir demandé trois fois l'argent pour un seul livre de calcul! Je n'avais qu'à <br/> demander, et ils me donnaient volontiers. Mais, quelquefois pour y arriver, il fallait mentir. Si je <br/> mentais pour demander un peu d'argent, ce n'était pas par méchanceté; c'était plutôt parce que je <br/> ne savais pas mieux. J'ai trouvé le jeu gai. <br/> D'ailleurs, je ne faisais pas que mentir. <br/> En classe, j'avais la réputation d'être l'un des meilleurs élèves. Même les instituteurs les <br/> moins indulgents ont reconnu en moi cette petite qualité. Je faisais l'école buissonnière, c'est <br/> vrai, mais je faisais de mon mieux pour rattraper le retard. Il est nécessaire aussi de signaler que <br/> mon habitude de faire l'école buissonnière s'arrêtait après la première semaine de la rentrée pour <br/> ne reprendre qu'après l'examen. Quand j'y pense aujourd 'hui, j'avoue que je trouve cette <br/> habitude maligne. N'est ce pas pour éviter les travaux de champs? <br/> Néanmoins, je passais une grande partie de mes vacances à la ferme non avec mon père, <br/> mais avec mon grand père. Mon père avait sa ferme, mais on s'amusait mieux avec mon grandpère. <br/> C'est chez celui-ci qu'on mangeait mieux. <br/> D'après Ajiboye, Tunde (2008) First Essays in French. <br/> Le père de l'auteur était généralement</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">méchant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avare</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ravailleur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">triste.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The text states 'Ma mère aimait m'acheter des friandises, mais mon père était un peu avare sur des questions de friandises', which translates to 'My mother liked to buy me treats, but my father was a bit stingy about treats'. This suggests that the father was stingy, which matches with the second option 'avare'.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> TEXTE II <br/> Lorsque j'étais enfant, ce que je faisais <br/> Mes souvenirs d'enfance sont remplis de beaucoup d'expériences intéressantes. Lorsque <br/> j'étais enfant, je cherchais toujours à être dans la compagnie des autres enfants comme moi. <br/> J'avais horreur de rester seul, si bien que je pleurais pendant des heures si je ne me voyais qu' <br/> entouré de solitude. <br/> Ma mère aimait m'acheter des friandises, mais mon père était un peu avare sur des <br/> questions de friandises. Chaque fois que maman n'était pas à la maison pour m'en donner, je <br/> devais faire semblant d'être malade pour que papa m'en achète. Et il faut imaginer combien de <br/> fois il me disait: \"Je sais que tu seras bientôt guéri\". <br/> Comme j'étais l'enfant unique de mes parents à cette époque-là, l'on comprendrait <br/> facilement pourquoi mon père, malgré son avarice, était bien indulgent envers moi. <br/> C'était à l'école que je profitais le plus de sa gentillesse et, bien sûr de celle de ma mère. <br/> Je me rappelle avoir demandé trois fois l'argent pour un seul livre de calcul! Je n'avais qu'à <br/> demander, et ils me donnaient volontiers. Mais, quelquefois pour y arriver, il fallait mentir. Si je <br/> mentais pour demander un peu d'argent, ce n'était pas par méchanceté; c'était plutôt parce que je <br/> ne savais pas mieux. J'ai trouvé le jeu gai. <br/> D'ailleurs, je ne faisais pas que mentir. <br/> En classe, j'avais la réputation d'être l'un des meilleurs élèves. Même les instituteurs les <br/> moins indulgents ont reconnu en moi cette petite qualité. Je faisais l'école buissonnière, c'est <br/> vrai, mais je faisais de mon mieux pour rattraper le retard. Il est nécessaire aussi de signaler que <br/> mon habitude de faire l'école buissonnière s'arrêtait après la première semaine de la rentrée pour <br/> ne reprendre qu'après l'examen. Quand j'y pense aujourd 'hui, j'avoue que je trouve cette <br/> habitude maligne. N'est ce pas pour éviter les travaux de champs? <br/> Néanmoins, je passais une grande partie de mes vacances à la ferme non avec mon père, <br/> mais avec mon grand père. Mon père avait sa ferme, mais on s'amusait mieux avec mon grandpère. <br/> C'est chez celui-ci qu'on mangeait mieux. <br/> D'après Ajiboye, Tunde (2008) First Essays in French. <br/> L'auteur préférait travailler à la ferme avec son grand-père parce qu'il</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">s'y reposait mieux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y dormait bien</div>", "<div style=\"font-family:Cambria;font-size:17px;\">s'y sentait mieux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y mangeait beaucoup.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the text, the author states 'C'est chez celui-ci qu'on mangeait mieux.' which translates to 'It's at his (grandfather's) place that we ate better.' This implies that the author preferred working on the farm with his grandfather because the food was better there, hence the correct answer is 'y mangeait beaucoup.' which translates to 'ate a lot there.'</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sur la grammaire et la structure. <br/>  <br/> Badagry ... Ikeja appartiennent au même État.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ou</div>", "<div style=\"font-family:Cambria;font-size:17px;\">et</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ni</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ne</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Badagry ne Ikeja appartiennent au même État. <br/>  <br/> Badagry and Ikeja belong to the same state.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> ... robe portez- vous?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Qu'elles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quelle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quoi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sentence '... robe portez- vous?' is asking 'Which dress are you wearing?' The correct word to use in this context is 'Quelle' which means 'Which' in English. Therefore, the correct sentence should be 'Quelle robe portez- vous?' meaning 'Which dress are you wearing?'</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> e veux seulement ces chaises - là; ... sont trop chères.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ceux-ci</div>", "<div style=\"font-family:Cambria;font-size:17px;\">celle-ci</div>", "<div style=\"font-family:Cambria;font-size:17px;\">celui-ci</div>", "<div style=\"font-family:Cambria;font-size:17px;\">celles-ci.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'celles-ci'. The question is referring to 'these chairs' which in French is 'ces chaises'. The pronoun 'celles-ci' is used to refer to feminine plural nouns in French, which in this case is 'chaises'. The other options 'ceux-ci', 'celle-ci', 'celui-ci' are incorrect because they refer to masculine or singular nouns.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Notre école vient d'acheter des tables modernes ... bois.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">en</div>", "<div style=\"font-family:Cambria;font-size:17px;\">au</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'en'. In French, 'en' is used before a noun to indicate the material something is made of. In this case, 'en bois' means 'made of wood'. The other options 'au', 'de', 'le' are incorrect because they are not used in this context.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Là, c'est ... oncle, un professeur au lycée.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">m'</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'mon'. In French, 'mon' is a possessive adjective used before masculine singular nouns to indicate ownership or relation. In this case, 'mon oncle' means 'my uncle'. The other options 'ma', 'm'', 'moi' are incorrect because they are not used in this context.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Il faut que nous ...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nous dépêchions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dépêchions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nous dépêchons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dépêchons.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Il faut que nous nous dépêchions. <br/>  <br/> It is necessary that we hurry.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Les ouvriers ...la plantation avant le coucher du soleil.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">avait quitté</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avaient quitté</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avez quitté</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aviez quitté</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'avaient quitté'. The phrase 'Les ouvriers ...la plantation avant le coucher du soleil.' translates to 'The workers ... the plantation before sunset.'. In French, the past participle 'quitté' (left) needs to agree with the subject in number and gender. 'Les ouvriers' is plural, so the auxiliary verb 'avoir' (to have) should be in its plural form 'avaient'.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Bientôt Tunde et Dotun changeront ... adresse.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">son </div>", "<div style=\"font-family:Cambria;font-size:17px;\">leur <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">leurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mon</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'leur'. The phrase 'Bientôt Tunde et Dotun changeront ... adresse.' translates to 'Soon Tunde and Dotun will change ... address.'. In French, the possessive adjective 'leur' (their) is used before a singular noun to indicate possession by more than one person. Since 'adresse' is singular and Tunde and Dotun are two people, 'leur' is the correct choice.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Je regrette ... mon action.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vif</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vivement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vivante</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'vivement'. In French, 'Je regrette vivement mon action' translates to 'I deeply regret my action'. The adverb 'vivement' is used to express a strong feeling or emotion. The other options do not fit grammatically or contextually in the sentence.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Le médecin est pressé, mais il doit écouter ... le malade.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">totalement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gravement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">patiemment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapidement</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'patiemment'. In French, 'Le médecin est pressé, mais il doit écouter patiemment le malade' translates to 'The doctor is in a hurry, but he must listen to the patient patiently'. The adverb 'patiemment' is used to express the manner in which the doctor should listen to the patient. The other options do not fit contextually in the sentence.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Après le déluge, aucune maison n'est restée</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debout</div>", "<div style=\"font-family:Cambria;font-size:17px;\">haut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dessus.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'debout'. In French, 'Après le déluge, aucune maison n'est restée debout' translates to 'After the flood, no house remained standing'. The adjective 'debout' is used to describe the state of the houses after the flood. The other options do not fit grammatically or contextually in the sentence.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Qu'ils ... d'accord ou pas, nous quittons aujourd'hui.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sont</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soient</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ont</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aient</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In this sentence, the correct word to use is 'soient' which is the subjunctive form of 'être' (to be). The subjunctive mood is used to express various states of unreality such as doubt, possibility, necessity, or action that has not yet occurred. In this case, 'Qu'ils ... d'accord ou pas, nous quittons aujourd'hui.' translates to 'Whether they agree or not, we are leaving today.' The subjunctive is used here because the action (them agreeing or not) is uncertain.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> La soeur de Olu est jolie ... ennuyeuse.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">et</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ou</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mais</div>", "<div style=\"font-family:Cambria;font-size:17px;\">donc</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct word to use in this sentence is 'mais' which means 'but'. The sentence 'La soeur de Olu est jolie ... ennuyeuse.' translates to 'Olu's sister is pretty but boring.' The conjunction 'mais' is used to express a contrast or contradiction between two statements.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> La réunion aura lieu ...les délégués soient peu nombreux.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dès que</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parce que</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quoique</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pendant que</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct phrase to use in this sentence is 'quoique' which means 'although'. The sentence 'La réunion aura lieu ...les délégués soient peu nombreux.' translates to 'The meeting will take place although the delegates are few.' The conjunction 'quoique' is used to express a contrast or contradiction between two statements.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Il réussira ...qu'il réponde à toutes les questions.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">afin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bien que</div>", "<div style=\"font-family:Cambria;font-size:17px;\">à condition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parce</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'à condition' which translates to 'provided that' in English. The sentence 'Il réussira ...qu'il réponde à toutes les questions.' translates to 'He will succeed ... provided that he answers all the questions.' This makes sense in the context of the sentence. The other options 'afin' (in order to), 'bien que' (although), and 'parce' (because) do not fit in the context of the sentence.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Il parle ...affaire impossible.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">d'un</div>", "<div style=\"font-family:Cambria;font-size:17px;\">d'une</div>", "<div style=\"font-family:Cambria;font-size:17px;\">d'en</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de la</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'd'une' which translates to 'of a' in English. The sentence 'Il parle ...affaire impossible.' translates to 'He speaks ... of an impossible affair.' This makes sense in the context of the sentence. The other options 'd'un' (of a masculine noun), 'd'en' (of it), and 'de la' (of the) do not fit in the context of the sentence.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Je n'ai pas visité ...cour royale, mais j'ai fait le tour du monde.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">de la</div>", "<div style=\"font-family:Cambria;font-size:17px;\">la</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le</div>", "<div style=\"font-family:Cambria;font-size:17px;\">du</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'la' which translates to 'the' in English. The sentence 'Je n'ai pas visité ...cour royale, mais j'ai fait le tour du monde.' translates to 'I did not visit ... the royal court, but I traveled around the world.' This makes sense in the context of the sentence. The other options 'de la' (of the), 'le' (the for masculine noun), and 'du' (of the for masculine noun) do not fit in the context of the sentence.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Les touristes étrangers peuvent compter sur le sens ...des Nigérians.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">de la queue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de l'hospitalité</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de l'exagération</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de la vitesse</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Les touristes étrangers peuvent compter sur le sens de l'exagération des Nigérians.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Quels aspects du programme avez-vous ...?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">retenu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retenues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retenez</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retenus</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question is asking about aspects of the program that you have 'retained' or 'remembered'. The verb 'retenir' means 'to retain' or 'to remember'. In this context, the past participle 'retenus' is used because 'aspects' is a masculine plural noun in French.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la grammaire et la structure. <br/> Quel est la séquence correcte?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Va cueillir des bouquets de rose!</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Va des bouquets de cueillir rose!</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cueillir va des bouquets de rose!</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Des bouquets va cueillir de rose!</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence in French for the given sentence is 'Va cueillir des bouquets de rose!'. In French, the verb usually comes before the object. So, 'Va' (Go) comes first, followed by 'cueillir' (to pick), then 'des bouquets de rose' (bouquets of roses). The other options do not follow the correct French sentence structure.</div>", "topic": "PRINCIPLES GOVERNING THE STRUCTURE AND USE OF WRITTEN FRENCH"}, {"id": "objective>French>2010>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Questions 31-40 sur l'Oral <br/>  <br/> Le son [o] se trouve dans</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eut</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sound [o] is found in the French word 'eau'. In French phonetics, the letter combination 'eau' is pronounced as [o].</div>", "topic": "WORKINGS OF FRENCH SOUNDS"}, {"id": "objective>French>2010>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> D'après un proverbe français, aide-toi et</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tes professeurs vont t'aider</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le ciel t' aidera</div>", "<div style=\"font-family:Cambria;font-size:17px;\">et tu vas réussir</div>", "<div style=\"font-family:Cambria;font-size:17px;\">les anges t'aideront.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The French proverb is 'Aide-toi, le ciel t'aidera' which translates to 'Help yourself, and heaven will help you'. Therefore, the correct answer is 'le ciel t'aidera'.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> Combien de syllabes y-a-t-il dans le mot \"camarade.\"</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are three syllables in the French word \"camarade.\"</div>", "topic": "WORKINGS OF FRENCH SOUNDS"}, {"id": "objective>French>2010>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> Quel ... ! La tempête a tout enlevé.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dommage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pitié</div>", "<div style=\"font-family:Cambria;font-size:17px;\">orage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bruit</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sentence 'Quel ... ! La tempête a tout enlevé.' translates to 'What a ...! The storm took everything away.' The correct word to fill in the blank is 'dommage' which means 'damage' in English. This is because the storm causing damage makes sense in this context.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> J'espère que mon ami, Dodo viendra. <br/> C'est-à dire: Je ... que Dodo viendra.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pense</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regrette</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demande.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sentence 'J'espère que mon ami, Dodo viendra. <br/> C'est-à dire: Je ... que Dodo viendra.' translates to 'I hope that my friend, Dodo will come. That is to say: I ... that Dodo will come.' The correct word to fill in the blank is 'pense' which means 'think' in English. This is because hoping for something is similar to thinking or expecting it to happen.</div>", "topic": "COMPREHENSION IN FRENCH"}, {"id": "objective>French>2010>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> Le son// se trouve à la fin du mot</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">forcer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vallée</div>", "<div style=\"font-family:Cambria;font-size:17px;\">valet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forcée</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sound /ɛ/ is found at the end of the word valet. /t/ is silent.</div>", "topic": "WORKINGS OF FRENCH SOUNDS"}, {"id": "objective>French>2010>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> L'expression au revoir a combien de syllabes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The French expression \"au revoir\" contains three syllables. It is pronounced as /o ʁə.vwaʁ/, breaking into \"au,\" \"re,\" and \"voir.\"</div>", "topic": "WORKINGS OF FRENCH SOUNDS"}, {"id": "objective>French>2010>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> \"Les trois oiseaux sont sur l'arbre\"; il y a une liaison entre</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oiseaux et sont</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trois et oiseaux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">les et trois</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sur et l'arbre.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In French, when a word ending in a normally silent consonant (like \"trois\", which ends in -s) is followed by a word beginning with a vowel or a silent h, a liaison is usually made. <br/>  <br/> So: <br/> \"trois oiseaux\" is pronounced [trwa zo.zo] <br/>  <br/> The -s in \"trois\" is pronounced as a /z/ sound linking to \"oiseaux\" <br/>  <br/> This liaison is mandatory (obligatory) in standard French</div>", "topic": "WORKINGS OF FRENCH SOUNDS"}, {"id": "objective>French>2010>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> Quel est le groupement qui correspond à une lecture normale?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">J'admire sa beauté mais je crains/son esprit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J'admire/sa beauté mais je crains son esprit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J'admire sa beauté/mais je crains son esprit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J'admire sa beauté mais/je crains son esprit.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In French, the natural break in a sentence, or where one would normally pause when speaking, is called a groupement. In the sentence 'J'admire sa beauté mais je crains son esprit', the most natural break would be after 'beauté', making 'J'admire sa beauté' and 'mais je crains son esprit' the two groupements. Therefore, the option 'J'admire sa beauté/mais je crains son esprit' is the correct one.</div>", "topic": "WORKINGS OF FRENCH SOUNDS"}, {"id": "objective>French>2010>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Questions 31-40 sur l'Oral <br/> Le son /e/ apparaît dans</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marché</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frère</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mère</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peu</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sound /e/ appears in the word 'marché'. In French, the letter 'e' followed by a consonant usually makes the /e/ sound.</div>", "topic": "WORKINGS OF FRENCH SOUNDS"}, {"id": "objective>French>2010>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sur la Littérature. <br/>  <br/> Le principal personnage de Sans famille, c'est</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rémi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mère Barberin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Joli-coeur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vitalis.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main character of 'Sans famille' is Rémi. 'Sans famille' is a French novel by Hector Malot. The story is about a young boy named Rémi, who is sold by his impoverished mother to a traveling artist named Vitalis.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> Un genre littéraire qui s'écrit sous forme de dialogue s'appelle</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">un roman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">un poème</div>", "<div style=\"font-family:Cambria;font-size:17px;\">un pièce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">un conte.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A literary genre that is written in the form of a dialogue is called a 'play' or 'pièce' in French. A play is a form of literature written by a playwright, usually consisting of dialogue or singing between characters, intended for theatrical performance rather than just reading.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> Dans Sans famille, on trouve que Monsieur et Madame Driscoll sont des</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mendiants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">voleurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aristocrates.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the novel 'Sans famille', Monsieur and Madame Driscoll are aristocrats. They are not beggars, sailors, or thieves. The novel 'Sans famille' is a French novel that tells the story of a young boy named Remi who is sold by his impoverished mother to a traveling artist named Vitalis. Monsieur and Madame Driscoll are characters in this novel who are depicted as aristocrats.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> \"Enfermer la femme, ça ne sert à rien\"! Qui dit ceci dans Chaque chose en son temps?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zénabou</div>", "<div style=\"font-family:Cambria;font-size:17px;\">El-Hadji</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dr. Mariama</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fatou</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Chaque chose en son temps by Ahmadou Kourouma, the line \"Enfermer la femme, ça ne sert à rien !\" is said by Dr. Mariama, a female character who represents a modern, educated, and liberated African woman.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> Qui est l'auteur de Chaque chose en son temps?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Margaret Kwakwa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Camara Laye</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tunde Ajiboye</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lynn Mbuko.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The author of Chaque chose en son temps is Lynn Mbuko, a Nigerian playwright and writer.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> La monnaie unique de la zone francophone de l'Afrique de l'ouest c'est</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">le cedi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">la livre</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le CFA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le FF</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question asks for the common currency in the Francophone region of West Africa. The correct answer is 'le CFA'. The CFA franc is the name of two currencies used in parts of West and Central African countries which are guaranteed by the French treasury.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> Dans laquelle de ces villes se trouve C. F. T. D au Nigéria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ilorin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Badagry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Keffi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The C.F.T.D (Centre for French Teaching and Documentation) is located in Jos, Nigeria.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> Un pays francophone de l'Afrique de l'ouest est</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">e Sénégal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">e Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le Kenya</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le Gabon.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question asks for a Francophone country in West Africa. The correct answer is 'le Sénégal'. Senegal is a country in West Africa where French is the official language.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> Nicolas Sarkozy a succedé à ... en France</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">F. Mitterand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G. d'Estaing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J. Chirac</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J.M. Lepen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nicolas Sarkozy a succédé à Jacques Chirac en tant que président de la France. Jacques Chirac a été président de 1995 à 2007, et Nicolas Sarkozy a pris ses fonctions en 2007.</div>", "topic": "CULTURE AND CIVILIZATION"}, {"id": "objective>French>2010>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Sur la Littérature. <br/> La fête nationale française est célébrée</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">le 14 juillet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le 20 juillet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le 2 juillet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">le 4 juillet.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">La fête nationale française, également connue sous le nom de Bastille Day, est célébrée le 14 juillet. Elle commémore la prise de la Bastille en 1789, un événement clé de la Révolution française.</div>", "topic": "CULTURE AND CIVILIZATION"}];
